import 'package:flutter/material.dart';import 'package:flutter_test/flutter_test.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import 'package:freiraum_parking/app/app.dart';
void main(){testWidgets('responsive smoke discovery to search', (tester) async {await tester.binding.setSurfaceSize(const Size(390,844));await tester.pumpWidget(const ProviderScope(child:FreiraumApp()));await tester.pumpAndSettle(const Duration(seconds:1));expect(find.text('Wohin möchtest du?'),findsOneWidget);await tester.tap(find.text('Wohin möchtest du?'));await tester.pumpAndSettle();await tester.tap(find.text('Messe Frankfurt').first);await tester.pump();expect(find.text('VW Golf'),findsOneWidget);expect(find.text('Stellplätze anzeigen'),findsOneWidget);});testWidgets('desktop layout shows side panel', (tester) async {await tester.binding.setSurfaceSize(const Size(1200,800));await tester.pumpWidget(const ProviderScope(child:FreiraumApp()));await tester.pumpAndSettle(const Duration(seconds:1));expect(find.text('FREIRAUM'),findsWidgets);});}
